// Battery Charging Strategy Calculator
// Calculates optimal charging during cheap/free rate period using Solcast forecast
// Outputs to HA helper entities consumed by the Supplemental Grid Charging automation
//
// ── CONFIGURATION ────────────────────────────────────────────────────────────
// Edit these constants to match your system:

const DAILY_HOUSEHOLD_CONSUMPTION = 30;        // ← REPLACE: estimated daily consumption kWh
const MIN_CHARGING_THRESHOLD = 1.0;            // Minimum deficit to trigger grid charging (kWh)
const FORECAST_UNCERTAINTY_BUFFER = 0.85;      // Apply 15% haircut to solar forecast
const FREE_PERIOD_START_HOUR = 11;             // ← REPLACE: cheap/free period start (24h)
const FREE_PERIOD_END_HOUR = 14;               // ← REPLACE: cheap/free period end (24h)
const MAX_CHARGING_RATE_KW = 16.8;             // ← REPLACE: your inverter max charge rate kW
                                               //   or use sensor.sigen_0_inverter_1_rated_charging_power
const FREE_PERIOD_MIN_CHARGE_RATE = 2.0;       // ← REPLACE: minimum charge rate during free period kW

// Deadband prevents excessive rate changes on small fluctuations
const CHARGE_RATE_DEADBAND_KW = 0.5;

// EMA smoothing factor for available PV (0=no smoothing, 1=full smoothing)
const PV_SMOOTHING_FACTOR = 0.3;

// EV charger latch: keep Remote EMS on for this many minutes after EV stops
const EV_LATCH_MINUTES = 20;                   // ← REPLACE: adjust to your EV charger behaviour

// ── SENSOR PARSING ───────────────────────────────────────────────────────────
let solarRemaining = parseFloat(msg.payload.solar_remaining) || 0;
let solarThisHour = (parseFloat(msg.payload.solar_this_hour) || 0) / 1000;
let solarNextHour = (parseFloat(msg.payload.solar_next_hour) || 0) / 1000;
let currentHouseholdPower = (parseFloat(msg.payload.household_power) || 0) / 1000;
let currentPVGeneration = (parseFloat(msg.payload.pv_generation) || 0) / 1000;
let currentDCChargerPower = parseFloat(msg.payload.dc_charger_power) || 0;

// Battery remaining capacity derived from SoC sensor
let batterySoCPercent = parseFloat(msg.payload.battery_soc) || 0;
let batteryRatedCapacity = parseFloat(msg.payload.battery_rated_capacity) || 33.6; // ← REPLACE fallback
let batteryRemainingCapacity = parseFloat(((1 - batterySoCPercent / 100) * batteryRatedCapacity).toFixed(2));

let dcChargerRunningState = msg.payload.dc_charger_state || "Idle";

// Parse sunset time
let sunsetHour = 18;
if (msg.payload.sunset_hour) {
    try {
        let sunsetDate = new Date(msg.payload.sunset_hour);
        sunsetHour = sunsetDate.getHours() + (sunsetDate.getMinutes() / 60);
    } catch (e) { sunsetHour = 18; }
}

// Guard: skip if key inputs are missing
if (msg.payload.solar_remaining === undefined ||
    msg.payload.battery_soc === undefined ||
    !msg.payload.sunset_hour ||
    msg.payload.pv_generation === undefined) {
    node.warn("Waiting for all sensor data...");
    return null;
}

// ── CONTEXT ──────────────────────────────────────────────────────────────────
let lastAppliedRate = context.get('lastChargeRateKW') || 0;
let lastPVForBattery = context.get('lastPVForBattery') || null;
let evLatchExpiry = context.get('evLatchExpiry') || 0;

let now = new Date();
let now_ms = Date.now();
let currentHour = now.getHours() + (now.getMinutes() / 60);
let hoursUntilEndOfDay = 24 - currentHour;

// ── EV CHARGER LATCH ─────────────────────────────────────────────────────────
// Catches: Charging, Preparing, Occupied states, or measurable power
// Latch holds evChargerActive true for EV_LATCH_MINUTES after last signal,
// preventing dropout during brief pauses (e.g. cell balancing) mid-charge
let evDetectedNow = dcChargerRunningState.toLowerCase().includes("occupied") ||
                    dcChargerRunningState.toLowerCase().includes("charging") ||
                    dcChargerRunningState.toLowerCase().includes("preparing") ||
                    currentDCChargerPower > 0.3;

if (evDetectedNow) {
    evLatchExpiry = now_ms + (EV_LATCH_MINUTES * 60 * 1000);
    context.set('evLatchExpiry', evLatchExpiry);
}

let evChargerActive = evDetectedNow || (now_ms < evLatchExpiry);
let evLatchActive = !evDetectedNow && (now_ms < evLatchExpiry);
let evLatchMinutesRemaining = evLatchActive ? Math.ceil((evLatchExpiry - now_ms) / 60000) : 0;

// ── SOLAR FORECAST ───────────────────────────────────────────────────────────
let minutesIntoHour = now.getMinutes();
let fractionOfHourRemaining = (60 - minutesIntoHour) / 60;
let proRataSolarThisHour = solarThisHour * fractionOfHourRemaining;
let enhancedSolarForecast = solarRemaining - solarThisHour + proRataSolarThisHour;
let conservativeSolarForecast = enhancedSolarForecast * FORECAST_UNCERTAINTY_BUFFER;

// ── CONSUMPTION ESTIMATE ─────────────────────────────────────────────────────
let effectiveSolarEndHour = sunsetHour - 2;
let hoursUntilSolarEnds = Math.max(0, effectiveSolarEndHour - currentHour);
let hourlyHouseholdConsumption = DAILY_HOUSEHOLD_CONSUMPTION / 24;
let estimatedRemainingConsumption = hourlyHouseholdConsumption * hoursUntilSolarEnds;
if (currentHouseholdPower > 2) { estimatedRemainingConsumption *= 1.2; }

// ── ENERGY BALANCE ───────────────────────────────────────────────────────────
let netAvailableEnergy = conservativeSolarForecast - estimatedRemainingConsumption;
let totalEnergyDeficit = Math.max(0, batteryRemainingCapacity - netAvailableEnergy);

// PV available for battery after household loads (EMA smoothed)
let rawAvailablePVForBattery = Math.max(0, currentPVGeneration - currentHouseholdPower);
let availablePVForBattery = lastPVForBattery === null ? rawAvailablePVForBattery :
    (PV_SMOOTHING_FACTOR * rawAvailablePVForBattery) + ((1 - PV_SMOOTHING_FACTOR) * lastPVForBattery);
context.set('lastPVForBattery', availablePVForBattery);

// ── SOLAR DURING FREE PERIOD ESTIMATE ────────────────────────────────────────
function estimateSolarDuringFreePeriod(currentHour, thisHourForecast, nextHourForecast) {
    let totalSolarKWh = 0;
    let avgSolarKW = 0;
    if (currentHour >= FREE_PERIOD_START_HOUR && currentHour < FREE_PERIOD_END_HOUR) {
        let hoursRemaining = FREE_PERIOD_END_HOUR - currentHour;
        let currentHourRemaining = Math.min(1, Math.ceil(currentHour) - currentHour);
        totalSolarKWh += thisHourForecast * currentHourRemaining;
        let fullHoursRemaining = Math.floor(hoursRemaining - currentHourRemaining);
        totalSolarKWh += nextHourForecast * fullHoursRemaining;
        let finalHourFraction = hoursRemaining - currentHourRemaining - fullHoursRemaining;
        if (finalHourFraction > 0) { totalSolarKWh += nextHourForecast * finalHourFraction * 0.9; }
        avgSolarKW = totalSolarKWh / hoursRemaining;
    } else if (currentHour < FREE_PERIOD_START_HOUR) {
        let hoursUntilFreePeriod = FREE_PERIOD_START_HOUR - currentHour;
        totalSolarKWh = hoursUntilFreePeriod < 1 ? nextHourForecast * 3 : nextHourForecast * 2.85;
        avgSolarKW = hoursUntilFreePeriod < 1 ? nextHourForecast : nextHourForecast * 0.95;
    }
    return avgSolarKW;
}

// ── CHARGING STRATEGY ────────────────────────────────────────────────────────
let suggestedChargeRateKW = 0;
let chargingDurationHours = 0;
let chargingStartTime = "";
let chargingEndTime = "";
let chargingMode = "NONE";
let reason = "";
let confidence = "medium";
let gridChargingRequired = false;

if (currentHour >= FREE_PERIOD_START_HOUR && currentHour < FREE_PERIOD_END_HOUR) {
    let hoursRemainingInFreePeriod = FREE_PERIOD_END_HOUR - currentHour;
    let solarSurplus = netAvailableEnergy - batteryRemainingCapacity;

    if (batteryRemainingCapacity < 0.1) {
        suggestedChargeRateKW = 0;
        chargingMode = "BATTERY_FULL";
        reason = "Battery full - self-consumption mode during free period";
        gridChargingRequired = false;
        confidence = "high";

    } else if (batteryRemainingCapacity > 1.0 && availablePVForBattery < 0.5) {
        suggestedChargeRateKW = Math.min(batteryRemainingCapacity / hoursRemainingInFreePeriod, MAX_CHARGING_RATE_KW);
        chargingMode = "GRID_CHARGING_PV_BUSY";
        reason = currentDCChargerPower > 1.0 ?
            `${batteryRemainingCapacity.toFixed(1)}kWh needed - PV busy with DC charger (${currentDCChargerPower.toFixed(1)}kW), charging ${suggestedChargeRateKW.toFixed(1)}kW from free grid` :
            `${batteryRemainingCapacity.toFixed(1)}kWh needed - PV busy with house loads, charging ${suggestedChargeRateKW.toFixed(1)}kW from free grid`;
        gridChargingRequired = true;
        confidence = "high";

    } else if (totalEnergyDeficit > MIN_CHARGING_THRESHOLD) {
        let currentSolarRate = availablePVForBattery;
        let targetBatteryFillRate = batteryRemainingCapacity / hoursRemainingInFreePeriod;
        let gridSupplementalRate = Math.max(0, targetBatteryFillRate - currentSolarRate);
        suggestedChargeRateKW = Math.min(targetBatteryFillRate, MAX_CHARGING_RATE_KW);
        chargingMode = "GRID_SUPPLEMENTAL";
        reason = `Deficit ${totalEnergyDeficit.toFixed(1)}kWh - charging at ${suggestedChargeRateKW.toFixed(1)}kW (${gridSupplementalRate.toFixed(1)}kW grid + ${currentSolarRate.toFixed(1)}kW solar) to fill by ${FREE_PERIOD_END_HOUR}:00`;
        if (currentDCChargerPower > 0.1) { reason += ` [DC charger: ${currentDCChargerPower.toFixed(1)}kW]`; }
        confidence = "high";
        gridChargingRequired = true;

    } else if (batteryRemainingCapacity > 3.0 && solarSurplus < 6.0) {
        let currentSolarRate = availablePVForBattery;
        let targetBatteryFillRate = batteryRemainingCapacity / hoursRemainingInFreePeriod;
        let naturalGridRate = Math.max(0, targetBatteryFillRate - currentSolarRate);
        let gridSupplementRate = Math.min(naturalGridRate, 3.0);
        suggestedChargeRateKW = Math.min(currentSolarRate + gridSupplementRate, MAX_CHARGING_RATE_KW);
        chargingMode = "OPPORTUNISTIC";
        reason = `${batteryRemainingCapacity.toFixed(1)}kWh needed, surplus ${solarSurplus.toFixed(1)}kWh - charging ${suggestedChargeRateKW.toFixed(1)}kW (${currentSolarRate.toFixed(1)}kW solar + ${gridSupplementRate.toFixed(1)}kW grid top-up)`;
        gridChargingRequired = true;
        confidence = "high";

    } else {
        suggestedChargeRateKW = 0;
        chargingMode = "SOLAR_ONLY";
        reason = batteryRemainingCapacity < 3.0 ?
            `Battery nearly full (${batterySoCPercent.toFixed(1)}% / ${batteryRemainingCapacity.toFixed(1)}kWh remaining) - solar charging naturally` :
            `${batteryRemainingCapacity.toFixed(1)}kWh needed (${batterySoCPercent.toFixed(1)}%), large surplus ${solarSurplus.toFixed(1)}kWh - solar sufficient`;
        gridChargingRequired = false;
        confidence = "high";
    }

    // EV Charger Override: keep Remote EMS on if EV active/latched during free period
    if (evChargerActive && !gridChargingRequired) {
        gridChargingRequired = true;
        if (batteryRemainingCapacity < 0.1) {
            suggestedChargeRateKW = FREE_PERIOD_MIN_CHARGE_RATE;
            chargingMode = "EV_CHARGER_KEEPALIVE";
            reason = evLatchActive ?
                `Battery full (${batterySoCPercent.toFixed(1)}%) - EV charger recently active (latch ${evLatchMinutesRemaining}min), keeping Remote EMS on for free grid EV charging` :
                `Battery full (${batterySoCPercent.toFixed(1)}%) - EV charger ${dcChargerRunningState} (${currentDCChargerPower.toFixed(1)}kW), keeping Remote EMS on for free grid EV charging`;
        } else {
            suggestedChargeRateKW = Math.min(batteryRemainingCapacity / hoursRemainingInFreePeriod, MAX_CHARGING_RATE_KW);
            chargingMode = "EV_CHARGER_GRID_SUPPLEMENTAL";
            reason = evLatchActive ?
                `${batteryRemainingCapacity.toFixed(1)}kWh needed (${batterySoCPercent.toFixed(1)}%) - EV charger recently active (latch ${evLatchMinutesRemaining}min), charging ${suggestedChargeRateKW.toFixed(1)}kW from free grid` :
                `${batteryRemainingCapacity.toFixed(1)}kWh needed (${batterySoCPercent.toFixed(1)}%) - EV charger ${dcChargerRunningState} (${currentDCChargerPower.toFixed(1)}kW), charging ${suggestedChargeRateKW.toFixed(1)}kW from free grid`;
        }
        confidence = "high";
    }

    if (gridChargingRequired) {
        let startHour = currentHour;
        let endHour = FREE_PERIOD_END_HOUR;
        chargingStartTime = Math.floor(startHour).toString().padStart(2,'0') + ':' + Math.floor((startHour%1)*60).toString().padStart(2,'0');
        chargingEndTime = endHour.toString().padStart(2,'0') + ':00';
        chargingDurationHours = hoursRemainingInFreePeriod;
    }

} else if (currentHour < FREE_PERIOD_START_HOUR) {
    let hoursInFreePeriod = FREE_PERIOD_END_HOUR - FREE_PERIOD_START_HOUR;
    let solarSurplus = netAvailableEnergy - batteryRemainingCapacity;

    if (batteryRemainingCapacity < 0.1) {
        chargingMode = "BATTERY_FULL";
        reason = `Battery full (${batterySoCPercent.toFixed(1)}%) - will remain in default mode`;
        confidence = "high";
        gridChargingRequired = false;

    } else if (totalEnergyDeficit > MIN_CHARGING_THRESHOLD) {
        let gridSupplementalRate = totalEnergyDeficit / hoursInFreePeriod;
        let forecastSolarAvgKW = estimateSolarDuringFreePeriod(currentHour, solarThisHour, solarNextHour);
        let forecastAvailableForBattery = Math.max(0, forecastSolarAvgKW - 1.0);
        suggestedChargeRateKW = Math.min(gridSupplementalRate + forecastAvailableForBattery, MAX_CHARGING_RATE_KW);
        chargingMode = "PLANNED_GRID_SUPPLEMENTAL";
        reason = `Deficit ${totalEnergyDeficit.toFixed(1)}kWh forecast (${batterySoCPercent.toFixed(1)}% SoC) - will charge ${suggestedChargeRateKW.toFixed(1)}kW (${gridSupplementalRate.toFixed(1)}kW grid + ${forecastAvailableForBattery.toFixed(1)}kW solar avg) at ${FREE_PERIOD_START_HOUR}:00`;
        confidence = currentHour > 9 ? "high" : "medium";
        gridChargingRequired = true;

    } else if (batteryRemainingCapacity > 3.0 && solarSurplus < 6.0) {
        let forecastSolarAvgKW = estimateSolarDuringFreePeriod(currentHour, solarThisHour, solarNextHour);
        suggestedChargeRateKW = Math.min(Math.max(forecastSolarAvgKW, FREE_PERIOD_MIN_CHARGE_RATE), MAX_CHARGING_RATE_KW);
        chargingMode = "PLANNED_OPPORTUNISTIC";
        reason = `${batteryRemainingCapacity.toFixed(1)}kWh needed (${batterySoCPercent.toFixed(1)}% SoC), surplus ${solarSurplus.toFixed(1)}kWh - will charge opportunistically at ${FREE_PERIOD_START_HOUR}:00`;
        confidence = currentHour > 9 ? "high" : "medium";
        gridChargingRequired = true;

    } else {
        chargingMode = "PLANNED_SOLAR_ONLY";
        reason = batteryRemainingCapacity < 3.0 ?
            `Battery nearly full (${batterySoCPercent.toFixed(1)}% / ${batteryRemainingCapacity.toFixed(1)}kWh remaining) - solar will complete charging` :
            `${batteryRemainingCapacity.toFixed(1)}kWh needed (${batterySoCPercent.toFixed(1)}% SoC), large surplus ${solarSurplus.toFixed(1)}kWh - solar sufficient`;
        confidence = currentHour > 9 ? "high" : "medium";
        gridChargingRequired = false;
    }

} else {
    suggestedChargeRateKW = 0;
    chargingMode = "AFTER_FREE_PERIOD";
    reason = "Free period ended - default self-consumption mode";
    confidence = "high";
    gridChargingRequired = false;
}

// Apply deadband
if (!gridChargingRequired || suggestedChargeRateKW === 0) {
    context.set('lastChargeRateKW', 0);
} else if (Math.abs(suggestedChargeRateKW - lastAppliedRate) < CHARGE_RATE_DEADBAND_KW && lastAppliedRate > 0) {
    suggestedChargeRateKW = lastAppliedRate;
}
context.set('lastChargeRateKW', suggestedChargeRateKW);

// Time context
let timeContext = "";
if (currentHour < FREE_PERIOD_START_HOUR - 1) {
    timeContext = "Planning phase - forecasts may change";
    if (confidence === "high") confidence = "medium";
} else if (currentHour >= FREE_PERIOD_START_HOUR - 1 && currentHour < FREE_PERIOD_START_HOUR) {
    timeContext = "Pre-charging assessment";
    confidence = "high";
} else if (currentHour >= FREE_PERIOD_START_HOUR && currentHour < FREE_PERIOD_END_HOUR) {
    timeContext = gridChargingRequired ? "Free period active - grid + solar" : "Free period active - solar only";
    confidence = "high";
} else {
    timeContext = "Free period ended";
}

// Output payload
msg.payload = {
    battery_soc_percent: batterySoCPercent,
    battery_remaining_capacity_kwh: batteryRemainingCapacity,
    battery_rated_capacity_kwh: batteryRatedCapacity,
    solar_remaining_today_kwh: solarRemaining,
    solar_this_hour_kwh: solarThisHour,
    solar_next_hour_kwh: solarNextHour,
    current_household_power_kw: currentHouseholdPower,
    current_pv_generation_kw: currentPVGeneration,
    current_dc_charger_power_kw: currentDCChargerPower,
    available_pv_for_battery_kw: availablePVForBattery,
    charging_required: gridChargingRequired,
    charging_mode: chargingMode,
    decision: gridChargingRequired ? "ENABLE_REMOTE_EMS" : "DEFAULT_MODE",
    reason: reason.substring(0, 250),
    confidence: confidence,
    time_context: timeContext.substring(0, 250),
    charging_rate_kw: parseFloat(suggestedChargeRateKW.toFixed(2)),
    charging_duration_hours: parseFloat(chargingDurationHours.toFixed(2)),
    charging_start_time: chargingStartTime,
    charging_end_time: chargingEndTime,
    charge_during_free_period: gridChargingRequired,
    ev_charger_running_state: dcChargerRunningState,
    ev_charger_active: evChargerActive,
    ev_charger_latch_active: evLatchActive,
    ev_charger_latch_minutes_remaining: evLatchMinutesRemaining,
    timestamp: new Date().toISOString()
};

return msg;
